/// <summary>
/// RestoreDeletedStack — POST /api/orgs/{orgName}/restore-stack/{programID}. Un-deletes a soft-deleted stack
/// by recreating it at its former coordinates and dropping the tombstone.
/// </summary>
public sealed class RestoreDeletedStackEndpoint(
    IStackStore stacks, IDeletedStackStore deletedStacks, IAuditLog audit) : EndpointWithoutRequest
{
    public override void Configure()
    {
        Post("/api/orgs/{orgName}/restore-stack/{programID}");
        AllowAnonymous();
        Description(b => b.WithTags("Organizations").WithSummary("RestoreDeletedStack").WithName("RestoreDeletedStack"));
    }

    public override async Task HandleAsync(CancellationToken ct)
    {
        var org = Route<string>("orgName")!;
        var programId = Route<string>("programID")!;
        var tombstone = deletedStacks.Get(org, programId);
        if (tombstone is null)
        {
            await Send.NotFoundAsync(ct);
            return;
        }

        var stackName = await ReadStackName(ct) ?? tombstone.StackName;
        var coords = new StackCoordinates(org, tombstone.ProjectName, stackName);
        if (!stacks.TryCreate(new StoredStack { Coordinates = coords }))
        {
            await Send.ErrorsAsync(409, ct); // a live stack already occupies those coordinates
            return;
        }

        deletedStacks.Remove(org, programId);
        audit.Record(org, "stack.restore", $"Restored stack '{coords.Qualified}'",
            RequestActor.From(User)?.Name ?? "happypumi");
        await Send.NoContentAsync(ct);
    }

